final:
module top_module(obf_D, sel, Q);input        [ 1:0] sel;          
   input        [15:0]   obf_D;          
   output  reg  [ 3:0]   Q;          

   always @ (obf_D, sel) begin

      case(sel)               
         2'b00:   Q = obf_D[3:0];       
         2'b01:   Q = obf_D[7:4];
         2'b10:   Q = obf_D[11:8];
         2'b11:   Q = obf_D[15:12];
         default: Q = obf_D[3:0];
      endcase

   end

endmodule
